    var mainBottomSource = AddEvolutionSource(state, 8154, "ST3-05", PlayerId.Player1, mainTarget.Id);
    var securityAttacker = AddBattlePermanent(state, 8155, 1855, "ST3-11", PlayerId.Player0, 0, enterTurn: 1);
