    };
    var blocker = AddBattlePermanent(state, 6322, 776, "FX-CANNOT-IGNORE", PlayerId.Player1, 0, enterTurn: 1);
    var target = AddBattlePermanent(state, 6323, 777, "FX-BLUE-L3", PlayerId.Player0, 0, enterTurn: 1);
