    state.CardDefinitions["FX-LOSE"] = CardEffectTestFixture.EffectDefinition("FX-LOSE", "FX_Lose");
    state.CardDefinitions["FX-SEC"] = CardEffectTestFixture.EffectDefinition("FX-SEC", "FX_Sec");
