    AddBattlePermanent(state, 9488, 1488, "FX-OPTIONAL-COUNTER", PlayerId.Player0, 1, enterTurn: 1);
    AddBattlePermanent(state, 9489, 1489, "FX-NEXT-COUNTER", PlayerId.Player0, 2, enterTurn: 1);
