        "ST1-09", "ST1-10", "ST1-11", "ST1-13", "ST1-14", "ST1-15", "ST1-16",
    })
    {
        AssertFalse(report.Errors.Any(error => error.Contains(cardId, StringComparison.Ordinal)));
    }
}

