        "fixture-exact",
        new[] { Asset("FX-01", 1, "base", "FX_01") },
        CardEffectTestFixture.Registry(new PrimitiveDrawCardScript("FX-01", "FX_01")),
        StatusSnapshot: new Dictionary<string, CardEffectPortingStatus>(StringComparer.Ordinal)
        {
