    AssertFalse(attacker.IsSuspended);

    attacker.IsSuspended = true;
    AssertThrows<DomainException>(() => pipeline.Run(
        state,
        EffectTiming.OnAllyAttack,
        PlayerId.Player0,
        values: new Dictionary<string, object?>
